import requests
from requests.auth import HTTPBasicAuth

rabbitmq_user = 'guest'
rabbitmq_password = 'guest'
rabbitmq_api_url = 'http://localhost:15672/api'

def create_vhost(vhost_name):
    url = f"{rabbitmq_api_url}/vhosts/{vhost_name}"
    response = requests.put(url, auth=HTTPBasicAuth(rabbitmq_user, rabbitmq_password))
    if response.status_code == 204:
        print(f'Successfully created vhost {vhost_name}')
    else:
        print(f'Failed to create vhost {vhost_name}: {response.text}')

def create_user(username, password):
    url = f"{rabbitmq_api_url}/users/{username}"
    payload = {
        "password": password,
        "tags": "management"
    }
    response = requests.put(url, json=payload, auth=HTTPBasicAuth(rabbitmq_user, rabbitmq_password))
    if response.status_code == 204:
        print(f'Successfully created user {username}')
    else:
        print(f'Failed to create user {username}: {response.text}')

def set_permissions(username, vhost_name, configure_regex='.*', write_regex='.*', read_regex='.*'):
    url = f"{rabbitmq_api_url}/permissions/{vhost_name}/{username}"
    payload = {
        "configure": configure_regex,
        "write": write_regex,
        "read": read_regex
    }
    response = requests.put(url, json=payload, auth=HTTPBasicAuth(rabbitmq_user, rabbitmq_password))
    if response.status_code == 204:
        print(f'Successfully set permissions for {username} on vhost {vhost_name}')
    else:
        print(f'Failed to set permissions for {username} on vhost {vhost_name}: {response.text}')

def setup_vhost_with_user(vhost_name, username, password):
    create_vhost(vhost_name)
    create_user(username, password)
    set_permissions(username, vhost_name)

# Example usage
setup_vhost_with_user('app1_vhost', 'app1_user', 'app1_password')
setup_vhost_with_user('app2_vhost', 'app2_user', 'app2_password')